namespace sv_6ac8e7ed630849f5a1ad78a780196245.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);

public record Message(
    int Id,
    int ChannelId,
    string Author,
    string Content,
    DateTime SentAt,
    int? ReplyToId,
    List<Reaction> Reactions);

public record Reaction(string Emoji, List<string> Users);

public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_6ac8e7ed630849f5a1ad78a780196245.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired]
    public Channel Channel { get; set; } = default!;

    [Parameter]
    public bool IsActive { get; set; }

    [Parameter]
    public EventCallback<Channel> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 50
            ? Channel.Description[..50] + "…"
            : Channel.Description;

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel);
}

.channel-item {
    padding: 0.6rem 0.75rem;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 0.4rem 0.15rem;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 0.1rem 0.45rem;
    border-radius: 10px;
    min-width: 1.2rem;
    text-align: center;
    flex-shrink: 0;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    margin-top: 0.15rem;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem 1rem;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 0.5rem 0.75rem;
    font-size: 0.9rem;
    resize: none;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #4a76a8;
}

.send-btn {
    padding: 0.5rem 1.2rem;
    background-color: #4a76a8;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.88rem;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
    height: fit-content;
}

.send-btn:hover:not(:disabled) {
    background-color: #3a6090;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_6ac8e7ed630849f5a1ad78a780196245.Services

<div class="message-bubble"
     @onmouseenter="ShowActions"
     @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge"
                        @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            💬 @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😊 React
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in AvailableEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public ThreadSummary? ThreadSummary { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] AvailableEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    private void ShowActions() => showActions = true;

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 0) return "just now";
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

