toolArgs.file_text:
.message-bubble {
    position: relative;
    padding: 0.5rem 1rem;
    border-radius: 6px;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.2rem;
}

.author {
    font-weight: 700;
    font-size: 0.92rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.92rem;
    color: #333;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.3rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    background: #eef1f5;
    border: 1px solid #dde1e6;
    border-radius: 12px;
    font-size: 0.82rem;
    cursor: pointer;
    transition: background-color 0.12s;
}

.reaction-badge:hover {
    background: #dde3eb;
}

.thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    font-size: 0.82rem;
    color: #4a76a8;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.15rem 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 0.2rem;
    right: 0.5rem;
    display: flex;
    gap: 0.2rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.15rem;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
}

.action-btn {
    padding: 0.25rem 0.5rem;
    border: none;
    background: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.78rem;
    color: #555;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: #f0f0f0;
}

.emoji-picker {
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 0.3rem;
    margin-top: 0.25rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    width: fit-content;
}

.emoji-btn {
    padding: 0.3rem;
    border: none;
    background: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1.2rem;
    line-height: 1;
}

.emoji-btn:hover {
    background-color: #f0f0f0;
}

