arguments.file_text:
@using sv_6ac8e7ed630849f5a1ad78a780196245.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int ActiveChannelId { get; set; }

    [Parameter]
    public EventCallback<Channel> OnChannelSelected { get; set; }
}

.channel-sidebar {
    background: #2c2f33;
    display: flex;
    flex-direction: column;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 1rem 0.75rem 0.5rem;
    border-bottom: 1px solid rgba(255,255,255,0.08);
}

.sidebar-header h3 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.35rem 0;
}

@using sv_6ac8e7ed630849f5a1ad78a780196245.Services
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h2># @ChannelName</h2>
        <p>@ChannelDescription</p>
    </div>
    <div class="message-list" @ref="messageListRef">
        @if (HasMoreMessages)
        {
            <div class="load-more-container">
                <button class="load-more-btn" @onclick="HandleLoadMore" disabled="@isLoadingMore">
                    @(isLoadingMore ? "Loading…" : "Load older messages")
                </button>
            </div>
        }
        @foreach (var message in Messages)
        {
            <MessageBubble Message="message"
