toolArgs.file_text:
@using sv_6ac8e7ed630849f5a1ad78a780196245.Services
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h2># @ChannelName</h2>
        <p>@ChannelDescription</p>
    </div>
    <div class="message-list" @ref="messageListRef">
        @if (HasMoreMessages)
        {
            <div class="load-more-container">
                <button class="load-more-btn" @onclick="HandleLoadMore" disabled="@isLoadingMore">
                    @(isLoadingMore ? "Loading…" : "Load older messages")
                </button>
            </div>
        }
        @foreach (var message in Messages)
        {
            <MessageBubble Message="message"
                           ThreadSummary="GetThreadSummary(message.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>
    <MessageInput OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired]
    public string ChannelName { get; set; } = "";

    [Parameter]
    public string ChannelDescription { get; set; } = "";

    [Parameter]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public List<ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter]
    public bool HasMoreMessages { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<MessageArea>? dotNetRef;
    private bool isLoadingMore;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./Components/Chat/MessageArea.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("init", messageListRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (HasMoreMessages && !isLoadingMore)
        {
            isLoadingMore = true;
            StateHasChanged();
            await OnLoadMore.InvokeAsync();
            isLoadingMore = false;
            StateHasChanged();
        }
    }

    private async Task HandleLoadMore()
    {
        isLoadingMore = true;
        await OnLoadMore.InvokeAsync();
        isLoadingMore = false;
    }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit may already be gone during prerender disposal
            }
        }
        dotNetRef?.Dispose();
    }
}

