@using sv_6ac8e7ed630849f5a1ad78a780196245.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <div class="quote-author">@RootMessage.Author</div>
            <div class="quote-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in Replies)
            {
                <MessageBubble Message="reply" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…" ButtonLabel="Reply" OnSend="OnReply" />
    }
</div>

@code {
    [Parameter]
    public Message? RootMessage { get; set; }

    [Parameter]
    public List<Message> Replies { get; set; } = [];

    [Parameter]
    public EventCallback OnClose { get; set; }

    [Parameter]
    public EventCallback<string> OnReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    background: #fafafa;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    width: 28px;
    height: 28px;
    border: none;
    background: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
    color: #666;
    display: flex;
    align-items: center;
    justify-content: center;
}

.close-btn:hover {
    background-color: #eee;
}

.thread-root-quote {
    margin: 0.75rem;
    padding: 0.6rem 0.75rem;
    background: #f0f4f8;
    border-left: 3px solid #4a76a8;
    border-radius: 4px;
    flex-shrink: 0;
}

.quote-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #1a1a1a;
    margin-bottom: 0.2rem;
}

.quote-content {
    font-size: 0.85rem;
    color: #444;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    text-align: center;
    padding: 0.35rem 0;
    flex-shrink: 0;
}

.thread-divider span {
    font-size: 0.75rem;
    color: #999;
    background: #fff;
    padding: 0 0.5rem;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 0.25rem 0;
}

