@page "/chat"
@using sv_6ac8e7ed630849f5a1ad78a780196245.Services
@using sv_6ac8e7ed630849f5a1ad78a780196245.Components.Chat
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout @(isThreadOpen ? "thread-open" : "")">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <MessageArea ChannelName="@selectedChannelName"
                 ChannelDescription="@selectedChannelDescription"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 HasMoreMessages="hasMoreMessages"
                 OnOpenThread="OpenThread"
                 OnReact="AddReaction"
                 OnSendMessage="SendMessage"
                 OnLoadMore="LoadOlderMessages" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private int selectedChannelId;
    private string selectedChannelName = "";
    private string selectedChannelDescription = "";
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private bool hasMoreMessages;
    private const int PageSize = 30;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannelId = channel.Id;
        selectedChannelName = channel.Name;
        selectedChannelDescription = channel.Description;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        hasMoreMessages = messages.Count == PageSize;
        threadSummaries = BuildThreadSummaries(messages);
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
        await ChatService.MarkChannelReadAsync(channel.Id);

        var idx = channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task LoadOlderMessages()
    {
        var older = await ChatService.GetMessagesAsync(selectedChannelId, messages.Count, PageSize);
        hasMoreMessages = older.Count == PageSize;
        messages.InsertRange(0, older);
        threadSummaries = BuildThreadSummaries(messages);
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        var thread = await ChatService.GetThreadAsync(rootMessageId);
        threadReplies = thread.Where(m => m.Id != rootMessageId).ToList();
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(
            selectedChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        threadSummaries = BuildThreadSummaries(messages);
    }

    private async Task AddReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        messages = await ChatService.GetMessagesAsync(
            selectedChannelId, 0, messages.Count);
    }

    private static List<ThreadSummary> BuildThreadSummaries(List<Message> msgs)
    {
        return msgs
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }
}

.chat-layout {
    display: grid;
    grid-template-columns: minmax(200px, 20%) 1fr;
    height: calc(100vh - 4.5rem);
    overflow: hidden;
    margin: -1rem -1.5rem -1rem -2rem;
    border-radius: 0;
}

.chat-layout.thread-open {
    grid-template-columns: minmax(200px, 20%) 1fr minmax(280px, 25%);
}

